import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{o as e,c as h,f as i}from"./app-7e9ead66.js";const r={},d=i('<h2 id="io口介绍" tabindex="-1"><a class="header-anchor" href="#io口介绍" aria-hidden="true">#</a> IO口介绍</h2><p>STM32的IO口相比51而言要复杂得多，所以使用起来也困难很多。首先STM32的IO口可以由软件配置成如下8种模式：</p><ol><li>输入浮空</li><li>输入上拉</li><li>输入下拉</li><li>模拟输入</li><li>开漏输出</li><li>推挽输出</li><li>推挽式复用功能</li><li>开漏复用功能</li></ol><h3 id="输入浮空" tabindex="-1"><a class="header-anchor" href="#输入浮空" aria-hidden="true">#</a> 输入浮空</h3><p>上拉/下拉电阻为断开状态，输入浮空模式下，IO 口的电平完全是由外部电路决定。如果 IO 引脚没有连接其他的设备，那么检测其输入电平是不确定的。</p><h3 id="输入上拉" tabindex="-1"><a class="header-anchor" href="#输入上拉" aria-hidden="true">#</a> 输入上拉</h3><p>上拉电阻导通，在需要外部上拉电阻的时候，可以使用内部上拉电阻，这样可以节省一个外部电阻，不适合做电流型驱动。</p><h3 id="输入下拉" tabindex="-1"><a class="header-anchor" href="#输入下拉" aria-hidden="true">#</a> 输入下拉</h3><p>下拉电阻导通，在需要外部下拉电阻的时候，可以使用内部下拉电阻，这样可以节省一个外部电阻，不适合做电流型驱动。</p><h3 id="模拟输入" tabindex="-1"><a class="header-anchor" href="#模拟输入" aria-hidden="true">#</a> 模拟输入</h3><p>上下拉电阻断开，用于 ADC、DAC、MCO这类操作模拟信号的外设。</p><h3 id="开漏输出" tabindex="-1"><a class="header-anchor" href="#开漏输出" aria-hidden="true">#</a> 开漏输出</h3><p>IO口引脚的电平状态会被采集到输入数据寄存器中，如果对输入数据寄存器进行读访问可以得到 IO口的状态。也就是说开漏输出模式下，我们可以读取 IO引脚状态。</p><h3 id="推挽输出" tabindex="-1"><a class="header-anchor" href="#推挽输出" aria-hidden="true">#</a> 推挽输出</h3><p>驱动能力较强，可以做电流型驱动，驱动电流最大可达25mA</p><h3 id="开漏复用功能" tabindex="-1"><a class="header-anchor" href="#开漏复用功能" aria-hidden="true">#</a> 开漏复用功能</h3><p>一个IO口可以是通用的IO口功能，还可以是其他外设的特殊功能引脚，这就是IO口的复用功能。</p><h2 id="led控制" tabindex="-1"><a class="header-anchor" href="#led控制" aria-hidden="true">#</a> LED控制</h2><p>使用GPIO的推挽输出模式</p><h2 id="蜂鸣器控制" tabindex="-1"><a class="header-anchor" href="#蜂鸣器控制" aria-hidden="true">#</a> 蜂鸣器控制</h2><p>使用GPIO的推挽输出模式</p><h2 id="按键输入" tabindex="-1"><a class="header-anchor" href="#按键输入" aria-hidden="true">#</a> 按键输入</h2><p>使用GPIO的输入模式，根据检测信号的电平来选择对应的输入模式。<br> 在没有外部上/下拉电阻时，使用STM32的内部的上下拉电阻，保证空闲信号的电平，当检测信号为高电平有效时，使用下拉输入模式，当检测信号为低电平有效时，使用上拉输入模式。</p>',23),n=[d];function t(l,c){return e(),h("div",null,n)}const p=a(r,[["render",t],["__file","IO口介绍.html.vue"]]);export{p as default};
